class Solution:
    def categorizeBox(self, length: int, width: int, height: int, mass: int) -> str:
        is_bulky = False
        if length >= 10000 or width >= 10000 or height >= 10000:
            is_bulky = True
        else:
            volume = length * width * height
            if volume >= 10**9:
                is_bulky = True
        is_heavy = mass >= 100
        if is_bulky and is_heavy:
            return "Both"
        elif is_bulky:
            return "Bulky"
        elif is_heavy:
            return "Heavy"
        else:
            return "Neither"

